;  ペンスキー峠

name = ペンスキー峠・高台
insideName = Summit
level = 10
bgm = forest
margin = 3
isOutdoor = true
shadow = dark
sky = mountain
showAllArea = true

; 画像パーツ
　 = grass
⏃ = woods
⑶ = br_agl

; 移動ポイント
(A) = map:ペンスキー峠・崖, x:2, y:5, fall:true
(B) = map:ペンスキー峠・崖, x:2, y:4, fall:true

[map]
;---------------------------------------------------------------------------------------------------------------
;    0   1   2   3   4   5   6   7  
  	▲	▲	▲	▲	▲	▲	▲	▲
 7▲▼▼▼▼▼▼▼▼▼▼▼▼▼▼▼▲
  	▼▼▼▼▼▼▼▼▼▼▼▼▼▼▼
 6▲▼▼▼▼▼▼▼▼▼▼▼▼▼▼▼▲
  	▼▼▼▼▼▼▼▼▼▼▼▼▼▼▼
 5	⏃⏃　　①　①　①　①▼▼▼▼▲
  	⏃⏃　　　　　　　　　▼▼▼▼
 4	⏃⏃　　①　①　①　①▼▼▼▼▲
  	⏃⏃　　　　　　　　　▼▼▼▼
 3	⏃⏃　　②　　　　　　▼▼▼▼▲
  	⏃⏃　　　　　　　　　▼▼▼▼
 2	⏃⏃　　②　　　　　　▼▼▼▼▲
  	⏃⏃⏃⏃■⏃⏃⏃　⏃⏃▼▼▼▼
 1	⏃⏃⏃⏃■⏃⏃⏃⑶⏃⏃▼▼▼▼▲
  			⏃⏃■⏃⏃⏃⏃⏃⏃	▲	▲
 0			⏃⏃■⏃⏃⏃⏃⏃⏃
  					▲
;    0   1   2   3   4   5   6   7  
