[correct]

pos[2][1].f.warp = "A";
pos[2][0].f.warp = "B";

[endmap]
;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

if(! loading && ! events.has(2)) events.push2(1);

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] party.lastIsMove

@delevent
@wait time=500 cond='WAY != "n"'
@walk turn=n cond='WAY != "n"'
@wait time=500

; シルフの個別イベントへ
[if exp='f.searcningSylphID !== void']
	@eval exp='game.curChara = game.chara[f.searcningSylphID]'
	[if exp='game.party.members.has(game.curChara)']
		@addevent name=マルエット num=3
		@eval exp='f.searcningSylphID = void'
		@jump storage="heroine05b.scn" target=*theo_04
	[endif]
[endif]

; シルフのイベント以外
[texton]
After climbing up the cliff, I found a plateau with a great view.[k]
There's a nice breeze blowing... Somehow, the air here feels very clear. It would feel wonderful to spend every day in a place like this.
 [k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

@delevent
@wait time=500
@walk move=n
@wait time=500
@walk move=e
@wait time=500
@walk move=e
@wait time=500
@walk move=n
@wait time=500
@eval exp='game.curChara = game.chara[f.visitingSylphID]'
@jump storage="heroine05b.scn" target=*theo_06

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("speed", 2)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Speed permanently increased by 2!"'

[eventoff]
;-------------------------------------------------------------------------------
